package com.anvritai.abhay.api;
import static com.anvritai.abhay.api.JobDtos.*;import com.anvritai.abhay.security.UserPrincipal;import com.anvritai.abhay.service.BackgroundJobService;import jakarta.validation.Valid;import java.util.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/companies/{companyId}/jobs") public class BackgroundJobController{private final BackgroundJobService service;public BackgroundJobController(BackgroundJobService s){service=s;}@PostMapping public JobResponse enqueue(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId,@Valid @RequestBody EnqueueJobRequest r){return service.enqueue(p.id(),companyId,r);}@GetMapping public List<JobResponse> list(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId){return service.list(p.id(),companyId);}@PostMapping("/{id}/run") public JobResponse run(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId,@PathVariable UUID id){return service.run(p.id(),companyId,id);}}
